import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.next();

        // Limiting the input size to 10 characters
        String sanitizedInput = input.substring(0, Math.min(input.length(), 10));

        // Initializing the buffer with correct size
        char[] buffer = new char[sanitizedInput.length()];

        // Copying the sanitized input into the buffer
        for (int i = 0; i < sanitizedInput.length(); i++) {
            buffer[i] = sanitizedInput.charAt(i);
        }

        System.out.println("Your name is: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
